const rows = $input.all();
const today = new Date().toISOString().split('T')[0];

let personalToday = 0, businessToday = 0;
let countToday = 0;
const topItems = [];

for (const row of rows) {
  const r = row.json;
  if (r.Date !== today || !r.Amount) continue;
  const amt = parseFloat(r.Amount) || 0;
  if (r.Type === 'Business') businessToday += amt;
  else personalToday += amt;
  countToday++;
  topItems.push(`  • ${r.Merchant} ₹${amt.toFixed(0)} (${r.Category})`);
}

const totalToday = personalToday + businessToday;

let msg;
if (countToday === 0) {
  msg = `📊 *Daily Summary — ${today}*\n\n✅ No expenses logged today!`;
} else {
  const itemLines = topItems.slice(0, 5).join('\n');
  msg = `📊 *Daily Summary — ${today}*\n\n${countToday} expense(s)\n👤 Personal: ₹${personalToday.toFixed(0)}\n💼 Business: ₹${businessToday.toFixed(0)}\n💰 Total: ₹${totalToday.toFixed(0)}\n\n*Today:*\n${itemLines}`;
}

return [{ json: { message: msg } }];
